(function () {
  const utils = window.IKSASS || {};
  const escapeHtml = utils.escapeHtml || ((value) => String(value || ''));
  const formatDate = utils.formatDateIDLong || ((value) => value || '');
  const toRootUrl = utils.toRootUrl || ((value) => String(value || ''));

  function $(selector, root) {
    return (root || document).querySelector(selector);
  }

  const sidebar = $('.news-sidebar');
  if (!sidebar) return;

  const slugCurrent = ((window.location.pathname || '').match(/\/berita\/([^/]+)\/?/) || [])[1] || '';
  const latestMount = sidebar.querySelector('[data-latest-news]');
  const popularMount = sidebar.querySelector('[data-popular-news]');
  if (!latestMount && !popularMount) return;

  function renderList(items, labelText) {
    return `<ul class="sidebar-news">${items.map((item) => {
      const href = toRootUrl(`berita/${item.slug}/`);
      const dateText = item.date_display || formatDate(item.date_iso) || '';
      const excerpt = item.excerpt || item.description || '';
      return `
<li class="sidebar-news__item">
  <div class="sidebar-news__thumb">
    <img src="${escapeHtml(toRootUrl(item.image || ''))}" alt="" loading="lazy" decoding="async"/>
  </div>
  <div class="sidebar-news__body">
    <div class="sidebar-news__meta">
      <span class="sidebar-label">${escapeHtml(labelText)}</span>
      ${item.date_iso ? `<time datetime="${escapeHtml(item.date_iso)}">${escapeHtml(dateText)}</time>` : `<span>${escapeHtml(dateText)}</span>`}
    </div>
    <a class="sidebar-news__title" href="${escapeHtml(href)}">${escapeHtml(item.title || '')}</a>
    ${excerpt ? `<p class="sidebar-news__excerpt">${escapeHtml(excerpt)}</p>` : ''}
  </div>
</li>`;
    }).join('')}</ul>`;
  }

  fetch(toRootUrl('berita/news-index.json'), { cache: 'no-store' })
    .then((response) => (response.ok ? response.json() : Promise.reject(new Error('news-index'))))
    .then((data) => {
      const cleaned = (Array.isArray(data) ? data : [])
        .filter((item) => item && item.slug && item.title)
        .map((item) => ({
          slug: item.slug,
          title: item.title,
          excerpt: item.excerpt,
          description: item.description,
          date_iso: item.date_iso || '',
          date_display: item.date_display || '',
          image: item.image || 'assets/img/og-default.png',
          popular_score: typeof item.popular_score === 'number' ? item.popular_score : 0,
        }));

      const latest = cleaned
        .filter((item) => item.slug !== slugCurrent)
        .sort((a, b) => (b.date_iso || '').localeCompare(a.date_iso || ''))
        .slice(0, 4);

      const popular = cleaned
        .filter((item) => item.slug !== slugCurrent)
        .sort((a, b) => (b.popular_score - a.popular_score) || (b.date_iso || '').localeCompare(a.date_iso || ''))
        .slice(0, 4);

      if (latestMount) latestMount.innerHTML = renderList(latest, 'Terkini');
      if (popularMount) popularMount.innerHTML = renderList(popular, 'Populer');
    })
    .catch(() => {});
})();
